// Deriva o status atual (Disponivel / Em Reuniao / Ausente)
// a partir dos eventos retornados pela API de calendario.
const agora = new Date();
return items.map(item => {
  const eventos = item.json.value || [];
  const emReuniao = eventos.find(e => new Date(e.start) <= agora && agora <= new Date(e.end));
  return { json: {
    id: item.json.id,
    nome: item.json.nome,
    statusAtual: emReuniao ? 'Em Reuniao' : 'Disponivel',
    reuniaoAtual: emReuniao ? { subject: emReuniao.subject, fim: emReuniao.endHora } : null,
    proximaReuniao: null
  } };
});
